import { useEffect, useState } from "react";
import "./CompanyBugHistory.css";

export default function CompanyBugHistory() {
  const [bugs, setBugs] = useState([]);
  const token = localStorage.getItem("token");

  useEffect(() => {
    fetch("http://localhost:5000/api/bugs/company/bugs", {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then(res => res.json())
      .then(data => setBugs(data.bugs || []));
  }, [token]);

  const approved = bugs.filter(b => b.status === "approved");
  const rejected = bugs.filter(b => b.status === "rejected");
  const duplicate = bugs.filter(b => b.status === "duplicate");

  return (
    <div className="company-page">
      <h1>📁 Bug History</h1>

      {/* === STAT WIDGETS === */}
      <div className="widgets">
        <div className="widget approved">
          <h2>{approved.length}</h2>
          <p>Approved Bugs</p>
        </div>

        <div className="widget rejected">
          <h2>{rejected.length}</h2>
          <p>Rejected Bugs</p>
        </div>

        <div className="widget duplicate">
          <h2>{duplicate.length}</h2>
          <p>Duplicate Bugs</p>
        </div>
      </div>

      {/* === BUG LISTS === */}
      <div className="bug-sections">

        <BugSection title="Approved Bugs" bugs={approved} />
        <BugSection title="Rejected Bugs" bugs={rejected} />
        <BugSection title="Duplicate Bugs" bugs={duplicate} />

      </div>
    </div>
  );
}

/* ===== Reusable Section Component ===== */
function BugSection({ title, bugs }) {
  return (
    <div className="bug-section">
      <h2>{title}</h2>

      {bugs.length === 0 ? (
        <p className="muted">No records.</p>
      ) : (
        bugs.map(bug => (
          <div className="bug-card" key={bug._id}>
            <h3>{bug.title}</h3>
            <span className={`status ${bug.status}`}>
              {bug.status}
            </span>

            {bug.duplicateOf && (
              <p className="duplicate-ref">
                Duplicate of: {bug.duplicateOf}
              </p>
            )}
          </div>
        ))
      )}
    </div>
  );
}
